import React, { useState, useEffect, useRef } from "react";
import { useNavigate } from "react-router-dom";
import useStore from "../../store/store";
import { hasPermission } from "../../utils/authUtils";
import ErrorMsgPopup from "../../components/popup/ErrorMsgPopup";
import CommonPopup from "../../components/popup/CommonPopup";
import MainSearch from "../../components/main/MainSearch";
import TableSearch from "../../components/table/TableSearch";
import { createTable } from "../../utils/tableConfig";
import { initialFilters } from "../../utils/tableEvent";
import { handleDownloadExcel } from "../../utils/tableExcel";
import styles from "../../components/table/TableSearch.module.css";
import menuManageData from "../../data/MenuManageInfo.json";

// Utility Functions
const fn_CellText = { editor: "input", editable: true };
const fn_CellNumber = { editor: "number", editorParams: { min: 0 }, editable: true };
const fn_CellSelect = (values) => ({ editor: "list", editorParams: { values, autocomplete: true }, editable: true });
const fn_CellButton = (label, className, onClick) => ({
  formatter: (cell) => {
    const button = document.createElement("button");
    button.className = `btn btn-sm ${className}`;
    button.innerText = label;
    button.onclick = () => onClick(cell.getRow());
    return button;
  },
});
const fn_HandleCellEdit = (cell, field, setData, initialData, isRowUnchanged, tableInstance) => {
  const rowId = cell.getRow().getData().MENUID;

  setTimeout(() => {
    const newValue = cell.getValue();

    setData((prevData) =>
      prevData.map((row) => {
        if (String(row.MENUID) === String(rowId)) {
          const updatedRow = { ...row, [field]: newValue };
          const initialRow = initialData.find((r) => r.MENUID === row.MENUID);

          updatedRow.isChanged =
            isRowUnchanged(updatedRow, initialRow) &&
            updatedRow.isDeleted === "N" &&
            updatedRow.isAdded === "N"
              ? "N"
              : "Y";

          return updatedRow;
        }
        return row;
      })
    );

    if (tableInstance.current) tableInstance.current.redraw();
  }, 0);
};

const fn_FormatUpperMenu = (cell, _ignored, formatMenuName) => {
  const rowData = cell.getRow().getData();
  const tableData = cell.getTable().getData();
  const parent = tableData.find((item) => String(item.MENUID) === String(rowData.UPPERMENUID));
  return parent ? formatMenuName(parent.MENUNM, parent.MENULEVEL) : "없음";
};

const MenuManageInfo = () => {
  const { user } = useStore();
  const navigate = useNavigate();

  // Search filter definitions
  const filterFields = [
    { id: "MENUNM", label: "메뉴명", type: "text", placeholder: "메뉴명 검색", width: "auto", height: "auto" },
    { id: "USEYN", label: "사용", type: "select", options: [{ value: "", label: "전체" }, { value: "Y", label: "사용" }, { value: "N", label: "미사용" }], width: "auto", height: "auto" },
  ];

  // Table filter definitions
  const filterTableFields = [
    { id: "filterSelect", label: "", type: "select", options: [{ value: "", label: "전체" }, { value: "MENUNM", label: "메뉴 이름" }, { value: "URL", label: "URL" }, { value: "USEYN", label: "사용" }] },
    { id: "filterText", label: "", type: "text", placeholder: "찾을 내용을 입력하세요", width: "200px" },
  ];

  // State definitions
  const [filters, setFilters] = useState(initialFilters(filterFields));
  const [tableFilters, setTableFilters] = useState(initialFilters(filterTableFields));
  const [loading, setLoading] = useState(false);
  const [data, setData] = useState([]);
  const [initialData, setInitialData] = useState([]);
  const [isSearched, setIsSearched] = useState(false);
  const [tableStatus, setTableStatus] = useState("initializing");
  const [error, setError] = useState(null);
  const [showAddPopup, setShowAddPopup] = useState(false);
  const [showUpperMenuPopup, setShowUpperMenuPopup] = useState(false);
  const [selectedMenuId, setSelectedMenuId] = useState(null);
  const [newMenu, setNewMenu] = useState({ MENUNM: "", UPPERMENUID: "", URL: "", MENULEVEL: "1", LEAFMENUYN: "Y", MENUORDER: "", USEYN: "Y" });
  const tableRef = useRef(null);
  const tableInstance = useRef(null);
  const isInitialRender = useRef(true);

  // Menu name formatting function
  const formatMenuName = (menuName, level) => (level <= 1 ? menuName : `${"  ".repeat(level - 1)}└${menuName}`);

  // Row comparison function
  const isRowUnchanged = (row, initialRow) => {
    if (!initialRow) return false;
    const isEqual =
      row.MENUNM === initialRow.MENUNM &&
      row.UPPERMENUID === initialRow.UPPERMENUID &&
      row.URL === initialRow.URL &&
      Number(row.MENULEVEL) === Number(initialRow.MENULEVEL) &&
      row.LEAFMENUYN === initialRow.LEAFMENUYN &&
      Number(row.MENUORDER) === Number(initialRow.MENUORDER) &&
      row.USEYN === initialRow.USEYN;

    return isEqual;
  };

  // Table column definitions
  const columns = [
    { headerHozAlign: "center", hozAlign: "center", title: "ID", field: "MENUID", sorter: "string", width: 100 },
    { headerHozAlign: "center", hozAlign: "left", title: "메뉴명", field: "MENUNM", sorter: "string", width: 200, ...fn_CellText, cellEdited: (cell) => fn_HandleCellEdit(cell, "MENUNM", setData, initialData, isRowUnchanged, tableInstance) },
    { headerHozAlign: "center", hozAlign: "center", title: "상위 ID", field: "UPPERMENUID", sorter: "string", width: 120, formatter: (cell) => fn_FormatUpperMenu(cell, data, formatMenuName), cellClick: (e, cell) => { setSelectedMenuId(cell.getRow().getData().MENUID); setNewMenu({ ...newMenu, UPPERMENUID: cell.getRow().getData().UPPERMENUID || "" }); setShowUpperMenuPopup(true); } },
    { headerHozAlign: "center", hozAlign: "left", title: "URL", field: "URL", sorter: "string", width: 300, ...fn_CellText, cellEdited: (cell) => fn_HandleCellEdit(cell, "URL", setData, initialData, isRowUnchanged, tableInstance) },
    { headerHozAlign: "center", hozAlign: "center", title: "레벨", field: "MENULEVEL", sorter: "number", width: 80, ...fn_CellSelect([1, 2, 3, 4, 5]), cellEdited: (cell) => fn_HandleCellEdit(cell, "MENULEVEL", setData, initialData, isRowUnchanged, tableInstance) },
    { headerHozAlign: "center", hozAlign: "center", title: "하위포함", field: "LEAFMENUYN", sorter: "string", width: 100, ...fn_CellSelect(["Y", "N"]), cellEdited: (cell) => fn_HandleCellEdit(cell, "LEAFMENUYN", setData, initialData, isRowUnchanged, tableInstance) },
    { headerHozAlign: "center", hozAlign: "center", title: "순서", field: "MENUORDER", sorter: "number", width: 80, ...fn_CellNumber, cellEdited: (cell) => fn_HandleCellEdit(cell, "MENUORDER", setData, initialData, isRowUnchanged, tableInstance) },
    { headerHozAlign: "center", hozAlign: "center", title: "사용", field: "USEYN", sorter: "string", width: 80, ...fn_CellSelect(["Y", "N"]), cellEdited: (cell) => fn_HandleCellEdit(cell, "USEYN", setData, initialData, isRowUnchanged, tableInstance) },
    { headerHozAlign: "center", hozAlign: "center", title: "작업대상", field: "applyTarget", sorter: "string", width: 100, formatter: (cell) => cell.getRow().getData().isChanged === "Y" ? "√" : "" },
    { headerHozAlign: "center", hozAlign: "center", title: "작업", field: "actions", width: 120, visible: true, ...fn_CellButton("삭제", `btn-danger ${styles.deleteButton}`, (row) => handleDelete(row)) },
  ];

  // Data load function
  const loadData = () => {
    setLoading(true);
    setIsSearched(true);
    setError(null);
    try {
      let filteredData = menuManageData;

      if (filters.MENUNM) filteredData = filteredData.filter((row) => row.MENUNM.toLowerCase().includes(filters.MENUNM.toLowerCase()));
      if (filters.USEYN) filteredData = filteredData.filter((row) => row.USEYN === filters.USEYN);
      const leveledData = filteredData.map((row) => ({
        ...row,
        MENULEVEL: calculateMenuLevel(row, filteredData),
        MENUORDER: Number(row.MENUORDER),
        isDeleted: "N",
        isEdited: "N",
        isAdded: "N",
      }));

      setData(leveledData);
      setInitialData(leveledData);
    } catch (err) {
      console.error("데이터 로드 실패:", err);
      setError("데이터 로드 실패: " + err.message);
      setData([]);
      setInitialData([]);
    } finally {
      setLoading(false);
    }
  };

  // Menu level calculation
  const calculateMenuLevel = (row, data, visited = new Set()) => {
    if (!row.UPPERMENUID) return 1;
    if (visited.has(row.MENUID)) return 1;
    visited.add(row.MENUID);
    const parent = data.find((item) => item.MENUID === row.UPPERMENUID);
    return parent ? calculateMenuLevel(parent, data, visited) + 1 : 1;
  };

  // Permission check
  useEffect(() => {
    if (!user || !hasPermission(user.auth, "menuManage")) navigate("/");
  }, [user, navigate]);

  // Table initialization
  useEffect(() => {
    if (!tableRef.current) {
      setError("테이블 컨테이너가 준비되지 않았습니다.");
      return;
    }
    try {
      tableInstance.current = createTable(tableRef.current, columns, [], {
        editable: true,
        rowFormatter: (row) => {
          const data = row.getData();
          const el = row.getElement();
          el.classList.remove(styles.deletedRow, styles.addedRow, styles.editedRow);

          if (data.isDeleted === "Y") el.classList.add(styles.deletedRow);
          else if (data.isAdded === "Y") el.classList.add(styles.addedRow);
          else if (data.isChanged === "Y") el.classList.add(styles.editedRow);
        },
      });
      if (!tableInstance.current) throw new Error("createTable returned undefined or null");
      setTableStatus("ready");
    } catch (err) {
      setTableStatus("error");
      setError("테이블 초기화 실패: " + err.message);
    }
    return () => {
      if (tableInstance.current) {
        tableInstance.current.destroy();
        tableInstance.current = null;
        setTableStatus("initializing");
      }
    };
  }, []);

  // Data update
  useEffect(() => {
    if (isInitialRender.current) {
      isInitialRender.current = false;
      return;
    }

    const table = tableInstance.current;

    if (!table || tableStatus !== "ready" || loading) return;

    // renderer가 준비된 경우에만 처리
    if (table.rowManager?.renderer) {
      table.setData(data);

    } else {
      console.warn("renderer가 아직 초기화되지 않았습니다.");
    }
    
  }, [data, loading, tableStatus, isSearched]);

  // Table filter application
  useEffect(() => {
    if (isInitialRender.current || !tableInstance.current || tableStatus !== "ready" || loading) return;
    const { filterSelect, filterText } = tableFilters;
    if (filterText && filterSelect) {
      tableInstance.current.setFilter(filterSelect, "like", filterText);
    } else if (filterText) {
      if (filterText !== "") {
        tableInstance.current.setFilter(
          [
            { field: "MENUNM", type: "like", value: filterText },
            { field: "URL", type: "like", value: filterText },
            { field: "USEYN", type: "like", value: filterText },
          ],
          "or"
        );
      } else {
        tableInstance.current.clearFilter();
      }
    } else if (filterSelect) {
      tableInstance.current.clearFilter();
    }
  }, [tableFilters.filterSelect, tableFilters.filterText, tableStatus, loading]);

  // Add button handler
  const handleAddClick = () => {
    setNewMenu({ MENUNM: "", UPPERMENUID: "", URL: "", MENULEVEL: "1", LEAFMENUYN: "Y", MENUORDER: "", USEYN: "Y" });
    setShowAddPopup(true);
  };

  // Add popup confirm handler
  const handleAddConfirm = () => {
    if (!newMenu.MENUNM.trim()) {
      setError("메뉴 이름을 입력해주세요.");
      return;
    }
    if (!newMenu.MENUORDER || isNaN(newMenu.MENUORDER)) {
      setError("메뉴 순서를 숫자로 입력해주세요.");
      return;
    }
    const newMenuId = `MENU${String(data.length + 1).padStart(4, "0")}`;
    const newRow = {
      MENUID: newMenuId,
      MENUNM: newMenu.MENUNM,
      UPPERMENUID: newMenu.UPPERMENUID,
      URL: newMenu.URL,
      MENULEVEL: newMenu.UPPERMENUID ? calculateMenuLevel({ UPPERMENUID: newMenu.UPPERMENUID, MENUID: newMenuId }, data) : parseInt(newMenu.MENULEVEL),
      LEAFMENUYN: newMenu.LEAFMENUYN,
      MENUORDER: parseInt(newMenu.MENUORDER),
      USEYN: newMenu.USEYN,
      isDeleted: "N",
      isEdited: "N",
      isAdded: "Y",
    };
    setData((prevData) => [newRow, ...prevData]);
    setShowAddPopup(false);
    setNewMenu({ MENUNM: "", UPPERMENUID: "", URL: "", MENULEVEL: "1", LEAFMENUYN: "Y", MENUORDER: "", USEYN: "Y" });
  };

  // Add popup cancel handler
  const handleAddCancel = () => {
    setShowAddPopup(false);
    setNewMenu({ MENUNM: "", UPPERMENUID: "", URL: "", MENULEVEL: "1", LEAFMENUYN: "Y", MENUORDER: "", USEYN: "Y" });
  };

  // Upper menu selection popup confirm handler
  const handleUpperMenuConfirm = () => {
    if (!selectedMenuId) return;

    const newUpperMenuId = newMenu.UPPERMENUID;
    const newLevel = newUpperMenuId
      ? calculateMenuLevel({ UPPERMENUID: newUpperMenuId, MENUID: selectedMenuId }, data)
      : 1;

    setData((prevData) =>
      prevData.map((row) => {
        if (row.MENUID === selectedMenuId) {
          const updatedRow = {
            ...row,
            UPPERMENUID: newUpperMenuId,
            MENULEVEL: newLevel,
          };
          const initialRow = initialData.find((r) => r.MENUID === row.MENUID);
          updatedRow.isChanged =
            isRowUnchanged(updatedRow, initialRow) &&
            row.isDeleted === "N" &&
            row.isAdded === "N"
              ? "N"
              : "Y";

          return updatedRow;
        }
        return row;
      })
    );

    if (tableInstance.current) {
      tableInstance.current.redraw();
    }

    setShowUpperMenuPopup(false);
    setSelectedMenuId(null);
    setNewMenu({
      MENUNM: "",
      UPPERMENUID: "",
      URL: "",
      MENULEVEL: "1",
      LEAFMENUYN: "Y",
      MENUORDER: "",
      USEYN: "Y",
    });
  };

  // Upper menu selection popup cancel handler
  const handleUpperMenuCancel = () => {
    setShowUpperMenuPopup(false);
    setSelectedMenuId(null);
    setNewMenu({ MENUNM: "", UPPERMENUID: "", URL: "", MENULEVEL: "1", LEAFMENUYN: "Y", MENUORDER: "", USEYN: "Y" });
  };

  // Delete handler
  const handleDelete = (row) => {
    const rowData = row.getData();
    if (rowData.isAdded === "Y") {
      setData((prevData) => prevData.filter((r) => r.MENUID !== rowData.MENUID));
    } else {
      const newIsDeleted = rowData.isDeleted === "Y" ? "N" : "Y";
      setData((prevData) =>
        prevData.map((r) =>
          r.MENUID === rowData.MENUID
            ? {
                ...r,
                isDeleted: newIsDeleted,
                isChanged: "Y",
              }
            : r
        )
      );
    }
    if (tableInstance.current) tableInstance.current.redraw();
  };

  // Save handler
  const handleSave = () => {
    const changedRows = data.filter((row) => row.isChanged === "Y");

    if (changedRows.length === 0) {
      alert("변경된 데이터가 없습니다.");
      return;
    }

    changedRows.forEach((row, index) => {
      console.log(`--- [${index + 1}] MENUID: ${row.MENUID} ---`);
      Object.entries(row).forEach(([key, value]) => {
        if (!["isChanged", "isDeleted", "isAdded"].includes(key)) {
          console.log(`${key}: ${value}`);
        }
      });
    });

    alert("테스트 모드: 콘솔에 작업대상 행 정보가 출력되었습니다.");
  };

  return (
    <div className={styles.container}>
      <ErrorMsgPopup show={!!error} onHide={() => setError(null)} message={error} />
      <MainSearch filterFields={filterFields} filters={filters} setFilters={setFilters} onSearch={loadData} />
      <TableSearch
        filterFields={filterTableFields}
        filters={tableFilters}
        setFilters={setTableFilters}
        onDownloadExcel={() => handleDownloadExcel(tableInstance.current, tableStatus, "MenuManage.xlsx")}
        buttonStyles={styles}
      >
        <div className={styles.btnGroupCustom}>
          <button className={styles.btn} onClick={handleAddClick}>
            추가
          </button>
          <button className={styles.btn} onClick={handleSave}>
            저장
          </button>
        </div>
      </TableSearch>
      <CommonPopup show={showAddPopup} onHide={handleAddCancel} onConfirm={handleAddConfirm} title="새 메뉴 추가">
        <div className={styles.smallFont}>
          <div className="mb-3">
            <label htmlFor="menuName" className="form-label">
              메뉴 이름
            </label>
            <input
              type="text"
              className="form-control"
              id="menuName"
              value={newMenu.MENUNM}
              onChange={(e) => setNewMenu({ ...newMenu, MENUNM: e.target.value })}
              placeholder="메뉴 이름을 입력하세요"
            />
          </div>
          <div className="mb-3">
            <label htmlFor="upperMenuId" className="form-label">
              상위 메뉴
            </label>
            <select
              className="form-select"
              id="upperMenuId"
              value={newMenu.UPPERMENUID}
              onChange={(e) => setNewMenu({ ...newMenu, UPPERMENUID: e.target.value })}
            >
              <option value="">없음 (1레벨)</option>
              {data.map((row) => (
                <option key={row.MENUID} value={row.MENUID}>
                  {formatMenuName(row.MENUNM, row.MENULEVEL)}
                </option>
              ))}
            </select>
          </div>
          <div className="mb-3">
            <label htmlFor="menuUrl" className="form-label">
              URL
            </label>
            <input
              type="text"
              className="form-control"
              id="menuUrl"
              value={newMenu.URL}
              onChange={(e) => setNewMenu({ ...newMenu, URL: e.target.value })}
              placeholder="URL을 입력하세요"
            />
          </div>
          <div className="mb-3">
            <label htmlFor="menuLevel" className="form-label">
              메뉴 레벨
            </label>
            <select
              className="form-select"
              id="menuLevel"
              value={newMenu.MENULEVEL}
              onChange={(e) => setNewMenu({ ...newMenu, MENULEVEL: e.target.value })}
            >
              {[1, 2, 3, 4, 5].map((level) => (
                <option key={level} value={level}>
                  {level}
                </option>
              ))}
            </select>
          </div>
          <div className="mb-3">
            <label htmlFor="leafMenuYn" className="form-label">
              리프 메뉴 여부
            </label>
            <select
              className="form-select"
              id="leafMenuYn"
              value={newMenu.LEAFMENUYN}
              onChange={(e) => setNewMenu({ ...newMenu, LEAFMENUYN: e.target.value })}
            >
              <option value="Y">Y</option>
              <option value="N">N</option>
            </select>
          </div>
          <div className="mb-3">
            <label htmlFor="menuOrder" className="form-label">
              메뉴 순서
            </label>
            <input
              type="number"
              className="form-control"
              id="menuOrder"
              value={newMenu.MENUORDER}
              onChange={(e) => setNewMenu({ ...newMenu, MENUORDER: e.target.value })}
              placeholder="메뉴 순서를 입력하세요"
            />
          </div>
          <div className="mb-3">
            <label htmlFor="useYn" className="form-label">
              사용 여부
            </label>
            <select
              className="form-select"
              id="useYn"
              value={newMenu.USEYN}
              onChange={(e) => setNewMenu({ ...newMenu, USEYN: e.target.value })}
            >
              <option value="Y">Y</option>
              <option value="N">N</option>
            </select>
          </div>
        </div>
      </CommonPopup>
      <CommonPopup show={showUpperMenuPopup} onHide={handleUpperMenuCancel} onConfirm={handleUpperMenuConfirm} title="상위 메뉴 선택">
        <div className="mb-3">
          <label htmlFor="upperMenuIdSelect" className="form-label">
            상위 메뉴
          </label>
          <select
            className="form-select"
            id="upperMenuIdSelect"
            value={newMenu.UPPERMENUID}
            onChange={(e) => setNewMenu({ ...newMenu, UPPERMENUID: e.target.value })}
          >
            <option value="">없음 (1레벨)</option>
            {data.filter((row) => row.MENUID !== selectedMenuId).map((row) => (
              <option key={row.MENUID} value={row.MENUID}>
                {formatMenuName(row.MENUNM, row.MENULEVEL)}
              </option>
            ))}
          </select>
        </div>
      </CommonPopup>
      <div className={styles.tableWrapper}>
        {tableStatus === "initializing" && <div>초기화 중...</div>}
        {loading && <div>로딩 중...</div>}
        {error && <div>{error}</div>}
        <div
          ref={tableRef}
          className={styles.tableSection}
          style={{ visibility: loading || tableStatus !== "ready" ? "hidden" : "visible" }}
        />
      </div>
    </div>
  );
};

export default MenuManageInfo;